const { ethers } = require('ethers');

class TokenSwapDApp {
  constructor(provider, signer) {
    this.provider = provider;
    this.signer = signer;
    this.signerAddress = null;
  }

  async init() {
    this.signerAddress = await this.signer.getAddress();
  }

  async approveToken(tokenAddress, spenderAddress, amount = ethers.constants.MaxUint256) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        "function approve(address spender, uint256 amount) returns (bool)"
      ], this.signer);
      
      const tx = await tokenContract.approve(spenderAddress, amount);
      await tx.wait();
      return tx;
    } catch (error) {
      throw new Error(`Approval failed: ${error.message}`);
    }
  }

  async swapTokens(
    tokenInAddress,
    tokenOutAddress,
    amountIn,
    amountOutMin,
    path,
    to,
    deadline
  ) {
    try {
      const routerAddress = "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D"; // Uniswap V2 Router
      
      const routerContract = new ethers.Contract(routerAddress, [
        "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] path, address to, uint deadline) returns (uint[] amounts)"
      ], this.signer);

      const tx = await routerContract.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        to,
        deadline
      );

      await tx.wait();
      return tx;
    } catch (error) {
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async getAllowance(tokenAddress, spenderAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        "function allowance(address owner, address spender) view returns (uint256)"
      ], this.provider);

      return await tokenContract.allowance(this.signerAddress, spenderAddress);
    } catch (error) {
      throw new Error(`Failed to get allowance: ${error.message}`);
    }
  }

  async getTokenBalance(tokenAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, [
        "function balanceOf(address account) view returns (uint256)"
      ], this.provider);

      return await tokenContract.balanceOf(this.signerAddress);
    } catch (error) {
      throw new Error(`Failed to get balance: ${error.message}`);
    }
  }

  async getQuote(tokenIn, tokenOut, amountIn) {
    try {
      const routerAddress = "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D";
      
      const routerContract = new ethers.Contract(routerAddress, [
        "function getAmountsOut(uint amountIn, address[] path) view returns (uint[] amounts)"
      ], this.provider);

      const amounts = await routerContract.getAmountsOut(amountIn, [tokenIn, tokenOut]);
      return amounts[1];
    } catch (error) {
      throw new Error(`Failed to get quote: ${error.message}`);
    }
  }

  async isApproved(tokenAddress, spenderAddress) {
    const allowance = await this.getAllowance(tokenAddress, spenderAddress);
    return allowance.gte(ethers.constants.MaxUint256);
  }
}

module.exports = TokenSwapDApp;